import{_ as a,o as t,c as l,ag as r}from"./chunks/framework.eQLvDOR_.js";const p=JSON.parse(`{"title":"karpathy-claude-rules","description":"","frontmatter":{"title":"karpathy-claude-rules","concept":"Karpathy 的 Claude 规则","concept_id":"karpathy-claude-rules","aliases":["Karpathy Principles","CLAUDE.md Rules"],"sources":["02_Library/Claude_Code_Skills/[Claude_Code_Skills] Google engineer automated 80% of his work with Claude Code. here's the exact system he built..md"],"related_concepts":["[[claude-code-mastery]]"],"created_at":"2026-04-18","last_compiled":"2026-04-18"},"headers":[],"relativePath":"wiki/concepts/karpathy-claude-rules.md","filePath":"wiki/concepts/karpathy-claude-rules.md","lastUpdated":null}`),s={name:"wiki/concepts/karpathy-claude-rules.md"};function i(o,e,d,u,c,h){return t(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="karpathy-的-claude-规则-karpathy-s-claude-rules" tabindex="-1">Karpathy 的 Claude 规则 (Karpathy&#39;s Claude Rules) <a class="header-anchor" href="#karpathy-的-claude-规则-karpathy-s-claude-rules" aria-label="Permalink to &quot;Karpathy 的 Claude 规则 (Karpathy&#39;s Claude Rules)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>由 Andrej Karpathy 总结并被社区广泛接受的一套用于指导 AI 编程行为的工程纪律。通过全局的说明文件强制压制大语言模型的自负行为。</p><h2 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h2><ul><li><strong>Think Before Coding (先思后写)</strong>：强制模型写出推导与取舍方案再落代码，防假设错误。</li><li><strong>Simplicity First (简洁性优先)</strong>：遏制大模型过度设计（Over-engineering）与引入不必要依赖的坏习惯。</li><li><strong>Surgical Changes (外科手术式修改)</strong>：极度克制代码改动，仅修改任务直接要求的部分，不动其他。（来源：<a href="/s/webclips/library/Claude_Code_Skills/Claude_Code_Skills - Google engineer automated 80percent of his work with Claude Code. here&#39;s the exact system he built..html">[Claude_Code_Skills] Google engineer automated 80% of his work with Claude Code. here&#39;s the exact system he built..md</a>）</li><li><strong>Goal-Driven Execution (目标驱动)</strong>：执行应当有测试目标和可验证的成功标准。</li></ul><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p>将这四项原则写入项目根目录下的 <code>CLAUDE.md</code>，能够使 Claude 等编码助手的破坏性改写和凭空制造抽象的概率从 40% 下降到 3%。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li><a href="/s/webclips/wiki/concepts/claude-code-mastery.html">claude-code-mastery</a> — 属于掌控 CLI 工具的基础能力。</li></ul>',9)])])}const _=a(s,[["render",i]]);export{p as __pageData,_ as default};
